SELECT ano, COUNT(*) as zonas FROM candidate_zone_results GROUP BY ano ORDER BY ano;
SELECT ano, COUNT(*) as com_cpf FROM candidate_results WHERE cpf IS NOT NULL AND cpf != '' GROUP BY ano ORDER BY ano;

